	@Test
	void cacheFilterAppliesConfiguredExpiryAndCanReset() throws Exception {
		CacheFilter filter = new CacheFilter();
		filter.init(TestFilterConfig.withParams("cache", "Cache-Control", String.valueOf(CacheFilter.MAX_EXPIRY + 99)));

		MockHttpServletResponse response = new MockHttpServletResponse();
		filter.doFilter(new MockHttpServletRequest(), response, new MockFilterChain());

		assertThat(response.getHeader("Cache-Control")).isEqualTo("max-age=" + CacheFilter.MAX_EXPIRY + ", public");

		filter.destroy();
		response = new MockHttpServletResponse();
		filter.doFilter(new MockHttpServletRequest(), response, new MockFilterChain());
		assertThat(response.getHeader("Cache-Control")).isNull();
	}

