	@Test
	void proxyCookieHandlerReadsAndWritesCookies() {
		CookieHandler cookieHandler = new CookieHandler("42");
		MockHttpServletRequest request = new MockHttpServletRequest();
		request.setContextPath("/ctx");
		request.setCookies(new Cookie("name", "value"), new Cookie("empty", ""));
		HttpServletResponse response = mock(HttpServletResponse.class);

		assertThat(cookieHandler.getCookie(request, response, "name")).isEqualTo("value");
		assertThat(cookieHandler.getCookieNullIfEmpty(request, response, "name")).isEqualTo("value");
		assertThat(cookieHandler.getCookieNullIfEmpty(request, response, "empty")).isNull();

		cookieHandler.addNewCookie(request, response, "new-cookie", "new-value");
		ArgumentCaptor<Cookie> cookieCaptor = ArgumentCaptor.forClass(Cookie.class);
		verify(response, times(3)).addHeader("Vary", "Cookie");
		verify(response, times(4)).addCookie(cookieCaptor.capture());
		assertThat(cookieCaptor.getAllValues()).extracting(Cookie::getName)
				.containsExactly("name", "name", "empty", "new-cookie");
		assertThat(cookieCaptor.getAllValues()).extracting(Cookie::getPath).containsOnly("/ctx");
		assertThat(cookieCaptor.getAllValues()).extracting(Cookie::getMaxAge).containsOnly(42);
		assertThat(cookieHandler.getMaxAge()).isEqualTo("42");
	}

